def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    ln_item = np.log1p(item)
    sq_item = item ** 2
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                temp_sum = 0
                for b in range(1, a * 2 + 1):
                    denom = (a + b + 0.1)
                    exp_part = np.exp(-ratio / denom)
                    trig_part = np.cos(ratio * b / (a + 1)) + np.sin(ratio / (b + 1))
                    temp_sum += (ratio - a) ** 6 / denom * exp_part * trig_part
                priority += temp_sum * np.log1p(ratio)
            priority += np.tanh(np.sqrt(ratio)) * 15
            if i % 2 == 0:
                priority += np.sin(ratio * i) * 3
            else:
                priority -= np.cos(ratio * i) * 3
        elif 4 < ratio <= 7:
            for p in range(1, int(np.ceil(ratio)) + 4):
                inner = 0
                for q in range(1, p + 3):
                    factor = np.log1p(abs(ratio - p)) * np.sin(ratio * p * q)
                    inner += factor / (q + 0.1)
                priority += np.tanh(inner) * 2
            priority += (np.exp(-ratio) + np.cos(ratio * 2)) * 8
            if bin_cap < item * 0.9:
                priority += np.sqrt(item * bin_cap) * 3
            else:
                priority -= np.log(bin_cap + 1) * 2
        elif 2 < ratio <= 4:
            s = 0
            for r in range(1, 15):
                poly_term = ((ratio - 2) ** r) / (r + 0.5)
                trig_term = np.sin(r * ratio) + np.cos(r * ratio / 2)
                s += poly_term * trig_term
            priority = s * np.tanh(5 - ratio) + np.log1p(ratio) * 7
            for j in range(1, 5):
                if (i + j) % 2 == 0:
                    priority += np.cos(j * ratio * i) / (j + 0.5)
                else:
                    priority -= np.sin(j * ratio * i) / (j + 0.5)
        elif 1 <= ratio <= 2:
            s = 0
            for n in range(1, 20):
                base = (2 - ratio) ** n / (n ** 1.5 + 1)
                trig = np.sin(n * ratio) * np.cos(n / (ratio + 0.1))
                s += base * trig
            priority = s + np.exp(-ratio) * 12
            if bin_cap > item * 1.2:
                priority -= np.sqrt(bin_cap / item) * 4
            else:
                priority += np.log1p(bin_cap) * 3.5
            for m in range(1, 6):
                priority += np.tanh(m * ratio * i) / (m + 0.3)
        elif 0.5 <= ratio < 1:
            s = 0
            for x in range(1, 10):
                pow_term = ((1 - ratio) ** x) / (x ** 2 + 1)
                trig_term = np.cos(x * ratio * item) - np.sin(x * ratio / (item + 0.1))
                s += pow_term * trig_term
            priority = s * np.tanh(ratio) + np.exp(-item / (bin_cap + 1)) * 10
            if int(item * ratio + i) % 5 == 0:
                priority *= np.log1p(bin_cap + 2)
            else:
                priority /= (np.sqrt(bin_cap + 1) + 1.5)
            for y in range(1, 7):
                priority += ((1 - ratio) ** y) * np.sin(y * ratio * i / (item + 1)) / (y + 0.7)
        elif 0.2 <= ratio < 0.5:
            s = 0
            for z in range(1, 12):
                power_term = ((0.5 - ratio) ** z) / (z * 3)
                trig_term = np.cos(z * ratio * 2) + np.sin(z * item / (bin_cap + 0.5))
                s += power_term * trig_term
            priority = s + 1 / (bin_cap + 2)
            if int(item * 0.8) % 3 == 0:
                priority *= 2.2
            else:
                priority /= 2.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 3.5
            else:
                priority -= np.exp(-ratio * 2) * 2.5
            for w in range(1, 8):
                priority += ((0.5 - ratio) ** w) / (w + 1) * np.sin(item * w * 0.7)
        else:
            s = 0
            for u in range(1, 15):
                power_term = ((0.2 - ratio) ** u) / (u * 4)
                trig_term = np.sin(u * item * 0.6) + np.cos(u * ratio * 1.3)
                s += power_term * trig_term
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.5) % 4 == 0:
                priority *= 2.8
            else:
                priority /= 2.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item + bin_cap) * 4.5
            else:
                priority -= np.exp(-ratio * 3) * 3.7
            for v in range(1, 10):
                priority += ((0.2 - ratio) ** v) / (v + 0.5) * np.cos(item * v * 0.9)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 0.7) * 0.5
            else:
                priority -= np.cos(ratio * (i + idx) * 0.8) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (bin_cap + i) % 6 == 0:
            priority += np.tanh((bin_cap - item) / (1 + abs(ratio))) * 4
        else:
            priority -= np.exp(-abs(bin_cap - item)) * 4.5
        priorities[i] = priority
    return priorities
